import{_ as r,o as a,c as o,a2 as l}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"電感深度研究","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/被動元件研究/電感深度研究.md","filePath":"Deep32Q知識庫/產業洞察/被動元件研究/電感深度研究.md"}'),i={name:"Deep32Q知識庫/產業洞察/被動元件研究/電感深度研究.md"};function n(e,t,s,d,h,g){return a(),o("div",null,[...t[0]||(t[0]=[l('<h1 id="電感深度研究" tabindex="-1">電感深度研究 <a class="header-anchor" href="#電感深度研究" aria-label="Permalink to &quot;電感深度研究&quot;">​</a></h1><p><strong>更新日期：2026-05-12</strong><strong>產出者：Dr.32 知識管家（subagent）</strong></p><hr><h2 id="_1-電感分類" tabindex="-1">1. 電感分類 <a class="header-anchor" href="#_1-電感分類" aria-label="Permalink to &quot;1. 電感分類&quot;">​</a></h2><table tabindex="0"><thead><tr><th>類型</th><th>英文</th><th>特點</th><th>主要應用</th></tr></thead><tbody><tr><td><strong>功率電感</strong> (Power Inductor)</td><td>Power Inductor</td><td>大電流、高飽和</td><td>DC-DC 轉換器</td></tr><tr><td><strong>訊號電感</strong> (Signal Inductor)</td><td>Signal/RF Inductor</td><td>高頻、低雜訊</td><td>通訊設備</td></tr><tr><td><strong>TLVR 電感</strong> (Trans-Inductor VR)</td><td>TLVR Coupled Inductor</td><td>雙繞組、快速瞬態響應</td><td>AI 伺服器電源</td></tr><tr><td><strong>共模濾波器</strong> (Common Mode Choke)</td><td>Common Mode Filter</td><td>雜訊抑制</td><td>資料傳輸線路</td></tr><tr><td><strong>鐵氧體磁珠</strong> (Ferrite Bead)</td><td>Ferrite Bead</td><td>高頻雜訊濾除</td><td>所有電子產品</td></tr></tbody></table><hr><h2 id="_2-全球市場規模" tabindex="-1">2. 全球市場規模 <a class="header-anchor" href="#_2-全球市場規模" aria-label="Permalink to &quot;2. 全球市場規模&quot;">​</a></h2><h3 id="總體市場" tabindex="-1">總體市場 <a class="header-anchor" href="#總體市場" aria-label="Permalink to &quot;總體市場&quot;">​</a></h3><ul><li><strong>2025年全球電感市場</strong>：約 <strong>$84.2 億</strong></li><li><strong>2026年預估</strong>：約 <strong>$89.1 億</strong>（+5.8% YoY）</li><li><strong>功率電感 2025</strong>：約 <strong>$37.1 億</strong>（最大細分市場）</li></ul><h3 id="tlvr-電感——ai-伺服器專用" tabindex="-1">TLVR 電感——AI 伺服器專用 <a class="header-anchor" href="#tlvr-電感——ai-伺服器專用" aria-label="Permalink to &quot;TLVR 電感——AI 伺服器專用&quot;">​</a></h3><ul><li><strong>2024年全球雙繞組 TLVR 電感市場</strong>：約 $1.33 億</li><li><strong>2025年預估</strong>：約 $1.45 億</li><li><strong>2032年預估</strong>：約 $2.35 億（CAGR 8.7%）</li><li><strong>另一估算</strong>：2025 年約 $5 億 → 2033 年 ~$9 億（CAGR 8%）</li><li><strong>AI 伺服器佔比</strong>：預計約 45% 的 TLVR 電感市場應用</li></ul><h3 id="ai-伺服器電源供應器-psu" tabindex="-1">AI 伺服器電源供應器 (PSU) <a class="header-anchor" href="#ai-伺服器電源供應器-psu" aria-label="Permalink to &quot;AI 伺服器電源供應器 (PSU)&quot;">​</a></h3><ul><li><strong>2024年</strong>：約 $23.65 億</li><li><strong>2030年預估</strong>：約 $84.29 億（CAGR 23.3%）</li><li>現代 AI 伺服器功耗為傳統伺服器的 <strong>3-5 倍</strong></li></ul><hr><h2 id="_3-台股供應鏈分析" tabindex="-1">3. 台股供應鏈分析 <a class="header-anchor" href="#_3-台股供應鏈分析" aria-label="Permalink to &quot;3. 台股供應鏈分析&quot;">​</a></h2><h3 id="臺慶科-tai-cheng-3357-—-tlvr-電感龍頭" tabindex="-1">臺慶科 (Tai-Cheng, 3357) — TLVR 電感龍頭 <a class="header-anchor" href="#臺慶科-tai-cheng-3357-—-tlvr-電感龍頭" aria-label="Permalink to &quot;臺慶科 (Tai-Cheng, 3357) — TLVR 電感龍頭&quot;">​</a></h3><ul><li><strong>TLVR 量產</strong>：2023 Q4 開始量產 AI 伺服器 TLVR 電感</li><li><strong>客戶認證</strong>：美國 GPU 開發商 + CSP 已認證，馬來廠量產中</li><li><strong>2025 展望</strong>：TLVR 為核心成長動能</li><li><strong>2026 展望</strong>：NVIDIA Blackwell + CSP ASIC AI 伺服器電感出貨增加</li><li><strong>營收預估</strong>：2025 年獲利 NT$10.56 億（EPS 10.26，近四年新高）</li><li><strong>2026 預估</strong>：營收逐季成長，兩位數增長</li><li><strong>新應用</strong>：800V+ HVDC 高壓直流，優化產品組合</li><li><strong>馬來廠</strong>：2026/7 通過汽車認證，地緣政治風險緩衝</li></ul><h3 id="奇力新-chilisin-2456-—-國巨集團子公司" tabindex="-1">奇力新 (Chilisin, 2456) — 國巨集團子公司 <a class="header-anchor" href="#奇力新-chilisin-2456-—-國巨集團子公司" aria-label="Permalink to &quot;奇力新 (Chilisin, 2456) — 國巨集團子公司&quot;">​</a></h3><ul><li><strong>收購</strong>：2021 年國巨集團 100% 收購，已終止上市</li><li><strong>產品線</strong>：金屬功率電感、訊號電感</li><li><strong>AI 伺服器切入</strong>：2025/1 起積極進入 AI 伺服器供應鏈</li><li><strong>AI 電感用量</strong>：Blackwell 架構下增加 2-3 倍，ASP 高 5-8 倍</li><li><strong>全球市場</strong>：與 TDK、太陽誘電共同佔據金屬功率電感重要份額</li></ul><h3 id="其他台廠" tabindex="-1">其他台廠 <a class="header-anchor" href="#其他台廠" aria-label="Permalink to &quot;其他台廠&quot;">​</a></h3><ul><li><strong>普思 (Pulse)</strong>：國巨集團電感產品線，與奇力新整合</li><li><strong>鈺鎧 (5228)</strong>：鐵氧體電感，車用 + 通訊</li></ul><hr><h2 id="_4-ai-電源管理電感需求" tabindex="-1">4. AI 電源管理電感需求 <a class="header-anchor" href="#_4-ai-電源管理電感需求" aria-label="Permalink to &quot;4. AI 電源管理電感需求&quot;">​</a></h2><h3 id="tlvr-技術背景" tabindex="-1">TLVR 技術背景 <a class="header-anchor" href="#tlvr-技術背景" aria-label="Permalink to &quot;TLVR 技術背景&quot;">​</a></h3><ul><li><strong>傳統 VR</strong>：單繞組電感，響應速度有限</li><li><strong>TLVR 雙繞組</strong>：快速瞬態響應（sub-1V 核心電壓、&gt;1000A 瞬態電流）</li><li><strong>GB200 需求</strong>：NVIDIA GB200 需要 sub-1V 核心電壓 + &gt;1000A 瞬態電流</li><li><strong>滲透率</strong>：從可選 → 標配，快速提升</li></ul><h3 id="ai-伺服器電感用量" tabindex="-1">AI 伺服器電感用量 <a class="header-anchor" href="#ai-伺服器電感用量" aria-label="Permalink to &quot;AI 伺服器電感用量&quot;">​</a></h3><ul><li><strong>傳統伺服器</strong>：每機 ~數百顆電感</li><li><strong>GB200 NVL72</strong>：每機櫃數萬顆電感（含 TLVR + 功率電感）</li><li><strong>ASP 差異</strong>：AI 伺服器電單價是一般產品高 5-8 倍</li></ul><hr><h2 id="_5-車用電子電感需求" tabindex="-1">5. 車用電子電感需求 <a class="header-anchor" href="#_5-車用電子電感需求" aria-label="Permalink to &quot;5. 車用電子電感需求&quot;">​</a></h2><h3 id="ev-adas-趨勢" tabindex="-1">EV/ADAS 趨勢 <a class="header-anchor" href="#ev-adas-趨勢" aria-label="Permalink to &quot;EV/ADAS 趨勢&quot;">​</a></h3><ul><li>每台 EV 使用的電感數量為燃油車的 <strong>5-10 倍</strong></li><li>ADAS 系統需要高可靠度電感</li><li><strong>車用功率電感市場</strong>：2025 ~$14 億 → 2035 ~$33 億（CAGR 8-9%）</li></ul><h3 id="鈺鎧-5228" tabindex="-1">鈺鎧 (5228) <a class="header-anchor" href="#鈺鎧-5228" aria-label="Permalink to &quot;鈺鎧 (5228)&quot;">​</a></h3><ul><li><strong>鐵氧體電感</strong>：車用照明、儀表板、天窗控制</li><li><strong>認證</strong>：QS9000, TS16949, IATF16949</li><li><strong>未來</strong>：電動車馬達驅動市場拓展</li></ul><hr><h2 id="_6-漲價動能" tabindex="-1">6. 漲價動能 <a class="header-anchor" href="#_6-漲價動能" aria-label="Permalink to &quot;6. 漲價動能&quot;">​</a></h2><h3 id="日系醞釀漲價-→-台廠轉單效應" tabindex="-1">日系醞釀漲價 → 台廠轉單效應 <a class="header-anchor" href="#日系醞釀漲價-→-台廠轉單效應" aria-label="Permalink to &quot;日系醞釀漲價 → 台廠轉單效應&quot;">​</a></h3><ul><li><strong>村田/太陽誘電</strong>：產能轉向高階 AI 產品，中低階市場留給台廠</li><li><strong>台廠轉單</strong>：國巨集團（奇力新 + 普思）、臺慶科承接</li><li><strong>漲價範圍</strong>：功率電感、TLVR 電感、共模濾波器</li></ul><h3 id="hvdc-高壓直流應用" tabindex="-1">HVDC 高壓直流應用 <a class="header-anchor" href="#hvdc-高壓直流應用" aria-label="Permalink to &quot;HVDC 高壓直流應用&quot;">​</a></h3><ul><li>AI 伺服器從 48V 轉向 400V+ HVDC 架構</li><li>高壓電感需求增加，台廠積極開發</li></ul><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><ol><li><strong>IntelMarketResearch</strong> (2026): Dual-Winding TLVR Inductor Market Report</li><li><strong>TrendForce</strong> (2026): AI Server PSU Market Forecast</li><li><strong>Digitimes</strong> (2023-2026): 臺慶科 TLVR、國巨集團整合</li><li><strong>CTEE / ChinaTimes</strong>: 臺慶科 2025-2026 營運展望</li><li><strong>CTEE</strong> (2025-01): 國巨集團收購奇力新後 AI 伺服器切入</li><li><strong>CMedia</strong>: 奇力新國巨集團整合分析</li><li><strong>BusinessResearchInsights</strong> (2026): PPTC and CPTC Market</li><li><strong>FactMR / FutureMarketInsights</strong> (2026): Automotive Power Inductor Market</li><li><strong>Vocus.cc</strong>: 臺慶科法說會摘要</li></ol>',42)])])}const b=r(i,[["render",n]]);export{c as __pageData,b as default};
